// src/App.js
import React from "react";
import { Routes, Route, Navigate } from "react-router-dom";
import Login from "./pages/Login";
import Register from "./pages/Register";
import Booking from "./pages/Booking";
import RideTrack from "./pages/RideTrack";
import History from "./pages/History";
import Profile from "./pages/Profile";
import AdminDashboard from "./pages/AdminDashboard";
import RiderDashboard from "./pages/dashboards/RiderDashboard";
import UserDashboard from "./pages/dashboards/UserDashboard";
import DocumentUpload from "./pages/DocumentUpload";
import Navbar from "./components/Navbar";

export default function App() {
  // Read auth state directly from localStorage so routing responds immediately
  const token = localStorage.getItem("token");
  const role = localStorage.getItem("role"); // "rider", "user", "admin", etc.

  const isAuth = Boolean(token);

  // helper to redirect logged-in users away from auth pages
  const redirectIfAuth = (fallback = "/") =>
    isAuth ? <Navigate to={role === "rider" ? "/rider-dashboard" : "/user-dashboard"} /> : fallback;

  return (
    <>
      <Navbar />
      <main style={{ padding: 20 }}>
        <Routes>
          {/* Root: redirect to appropriate dashboard if logged in */}
          <Route
            path="/"
            element={
              isAuth ? (
                role === "rider" ? (
                  <Navigate to="/rider-dashboard" />
                ) : (
                  <Navigate to="/user-dashboard" />
                )
              ) : (
                <Navigate to="/login" />
              )
            }
          />

          {/* Auth pages: if already logged in -> redirect to dashboard */}
          <Route
            path="/login"
            element={isAuth ? <Navigate to={role === "rider" ? "/rider-dashboard" : "/user-dashboard"} /> : <Login />}
          />
          <Route
            path="/register"
            element={isAuth ? <Navigate to={role === "rider" ? "/rider-dashboard" : "/user-dashboard"} /> : <Register />}
          />

          {/* Rider-specific pages */}
          <Route
            path="/rider-dashboard"
            element={isAuth && role === "rider" ? <RiderDashboard /> : <Navigate to="/login" />}
          />
          <Route
            path="/upload-docs"
            element={isAuth && role === "rider" ? <DocumentUpload /> : <Navigate to="/login" />}
          />

          {/* User-specific */}
          <Route
            path="/user-dashboard"
            element={isAuth && role === "user" ? <UserDashboard /> : <Navigate to="/login" />}
          />

          {/* Common pages (require any authenticated user) */}
          <Route path="/booking" element={isAuth ? <Booking /> : <Navigate to="/login" />} />
          <Route path="/ride/:id" element={isAuth ? <RideTrack /> : <Navigate to="/login" />} />
          <Route path="/history" element={isAuth ? <History /> : <Navigate to="/login" />} />
          <Route path="/profile" element={isAuth ? <Profile /> : <Navigate to="/login" />} />

          {/* Admin */}
          <Route
            path="/admin"
            element={isAuth && role === "admin" ? <AdminDashboard /> : <Navigate to="/login" />}
          />

          {/* Catch-all */}
          <Route path="*" element={<div>404 Not Found</div>} />
        </Routes>
      </main>
    </>
  );
}
